PRAGMA foreign_keys = OFF;
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:1', 69, 1, 29, 566, 5324, 'اَلْحَاۤقَّةُۙ', 'Al-Ḥāqqah (hari Kiamat yang pasti datang).', '', 'https://everyayah.com/data/Alafasy_128kbps/069001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:2', 69, 2, 29, 566, 5325, 'مَا الْحَاۤقَّةُ ۚ ', 'Apakah al-Ḥāqqah itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/069002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:3', 69, 3, 29, 566, 5326, 'وَمَآ اَدْرٰىكَ مَا الْحَاۤقَّةُ ۗ ', 'Tahukah kamu apakah al-Ḥāqqah itu?', '', 'https://everyayah.com/data/Alafasy_128kbps/069003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:4', 69, 4, 29, 566, 5327, 'كَذَّبَتْ ثَمُوْدُ وَعَادٌ ۢبِالْقَارِعَةِ ', '(Kaum) Samud dan ‘Ad telah mendustakan al-Qāri‘ah (hari Kiamat yang menggetarkan hati).', '', 'https://everyayah.com/data/Alafasy_128kbps/069004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:5', 69, 5, 29, 566, 5328, 'فَاَمَّا ثَمُوْدُ فَاُهْلِكُوْا بِالطَّاغِيَةِ ', 'Adapun (kaum) Samud, mereka telah dibinasakan dengan suara yang sangat keras,', '', 'https://everyayah.com/data/Alafasy_128kbps/069005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:6', 69, 6, 29, 566, 5329, 'وَاَمَّا عَادٌ فَاُهْلِكُوْا بِرِيْحٍ صَرْصَرٍ عَاتِيَةٍۙ', 'sedangkan (kaum) ‘Ad telah dibinasakan dengan angin topan yang sangat dingin.', '', 'https://everyayah.com/data/Alafasy_128kbps/069006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:7', 69, 7, 29, 566, 5330, 'سَخَّرَهَا عَلَيْهِمْ سَبْعَ لَيَالٍ وَّثَمٰنِيَةَ اَيَّامٍۙ حُسُوْمًا فَتَرَى الْقَوْمَ فِيْهَا صَرْعٰىۙ  كَاَنَّهُمْ اَعْجَازُ نَخْلٍ خَاوِيَةٍۚ', 'Dia menimpakan angin itu kepada mereka selama tujuh malam delapan hari terus-menerus. Maka, kamu melihat kaum (‘Ad) pada waktu itu mati bergelimpangan seperti batang-batang pohon kurma yang telah (lapuk) bagian dalamnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/069007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:8', 69, 8, 29, 566, 5331, 'فَهَلْ تَرٰى لَهُمْ مِّنْۢ بَاقِيَةٍ ', 'Adakah kamu melihat seorang pun yang masih tersisa di antara mereka?', '', 'https://everyayah.com/data/Alafasy_128kbps/069008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:9', 69, 9, 29, 567, 5332, 'وَجَاۤءَ فِرْعَوْنُ وَمَنْ قَبْلَهٗ وَالْمُؤْتَفِكٰتُ بِالْخَاطِئَةِۚ', 'Begitu juga, Firʻaun dan orang-orang yang sebelumnya serta (penduduk) negeri-negeri yang dijungkirbalikkan datang dengan membawa kesalahan yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/069009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:10', 69, 10, 29, 567, 5333, 'فَعَصَوْا رَسُوْلَ رَبِّهِمْ فَاَخَذَهُمْ اَخْذَةً رَّابِيَةً ', 'Mereka mendurhakai utusan Tuhannya, lalu Dia menyiksa mereka dengan siksaan yang sangat keras.', '', 'https://everyayah.com/data/Alafasy_128kbps/069010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:11', 69, 11, 29, 567, 5334, 'اِنَّا لَمَّا طَغَا الْمَاۤءُ حَمَلْنٰكُمْ فِى الْجَارِيَةِۙ', 'Sesungguhnya ketika air naik (sampai ke gunung), Kami membawa (nenek moyang)-mu ke dalam (bahtera) yang berlayar', '', 'https://everyayah.com/data/Alafasy_128kbps/069011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:12', 69, 12, 29, 567, 5335, 'لِنَجْعَلَهَا لَكُمْ تَذْكِرَةً وَّتَعِيَهَآ اُذُنٌ وَّاعِيَةٌ ', 'agar Kami jadikan (peristiwa) itu sebagai peringatan bagi kamu dan agar diperhatikan oleh telinga yang mau mendengar.', '', 'https://everyayah.com/data/Alafasy_128kbps/069012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:13', 69, 13, 29, 567, 5336, 'فَاِذَا نُفِخَ فِى الصُّوْرِ نَفْخَةٌ وَّاحِدَةٌ ۙ', 'Apabila sangkakala ditiup dengan sekali tiupan', '', 'https://everyayah.com/data/Alafasy_128kbps/069013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:14', 69, 14, 29, 567, 5337, 'وَّحُمِلَتِ الْاَرْضُ وَالْجِبَالُ فَدُكَّتَا دَكَّةً وَّاحِدَةًۙ', 'dan bumi serta gunung-gunung diangkat lalu dibenturkan dengan sekali benturan,', '', 'https://everyayah.com/data/Alafasy_128kbps/069014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:15', 69, 15, 29, 567, 5338, 'فَيَوْمَىِٕذٍ وَّقَعَتِ الْوَاقِعَةُۙ', 'pada hari itu terjadilah kiamat.', '', 'https://everyayah.com/data/Alafasy_128kbps/069015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:16', 69, 16, 29, 567, 5339, 'وَانْشَقَّتِ السَّمَاۤءُ فَهِيَ يَوْمَىِٕذٍ وَّاهِيَةٌۙ', 'Langit juga terbelah karena pada hari itu ia rapuh.', '', 'https://everyayah.com/data/Alafasy_128kbps/069016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:17', 69, 17, 29, 567, 5340, 'وَّالْمَلَكُ عَلٰٓى اَرْجَاۤىِٕهَاۗ وَيَحْمِلُ عَرْشَ رَبِّكَ فَوْقَهُمْ يَوْمَىِٕذٍ ثَمٰنِيَةٌ  ۗ', 'Para malaikat berada di berbagai penjurunya (langit). Pada hari itu delapan malaikat menjunjung ʻArasy (singgasana) Tuhanmu di atas mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/069017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:18', 69, 18, 29, 567, 5341, 'يَوْمَىِٕذٍ تُعْرَضُوْنَ لَا تَخْفٰى مِنْكُمْ خَافِيَةٌ ', 'Pada hari itu kamu dihadapkan (kepada Tuhanmu). Tidak ada sesuatu pun dari kamu yang tersembunyi.', '', 'https://everyayah.com/data/Alafasy_128kbps/069018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:19', 69, 19, 29, 567, 5342, 'فَاَمَّا مَنْ اُوْتِيَ كِتٰبَهٗ بِيَمِيْنِهٖ فَيَقُوْلُ هَاۤؤُمُ اقْرَءُوْا كِتٰبِيَهْۚ ', 'Adapun orang yang diberi catatan amalnya di tangan kanannya, dia berkata (kepada orang-orang di sekelilingnya), “Ambillah (dan) bacalah kitabku (ini)!', '', 'https://everyayah.com/data/Alafasy_128kbps/069019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:20', 69, 20, 29, 567, 5343, 'اِنِّيْ ظَنَنْتُ اَنِّيْ مُلٰقٍ حِسَابِيَهْۚ', 'Sesungguhnya (saat di dunia) aku yakin bahwa (suatu saat) aku akan menerima perhitungan diriku.”', '', 'https://everyayah.com/data/Alafasy_128kbps/069020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:21', 69, 21, 29, 567, 5344, 'فَهُوَ فِيْ عِيْشَةٍ رَّاضِيَةٍۚ', 'Maka, ia berada dalam kehidupan yang menyenangkan', '', 'https://everyayah.com/data/Alafasy_128kbps/069021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:22', 69, 22, 29, 567, 5345, 'فِيْ جَنَّةٍ عَالِيَةٍۙ', 'dalam surga yang tinggi ', '', 'https://everyayah.com/data/Alafasy_128kbps/069022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:23', 69, 23, 29, 567, 5346, 'قُطُوْفُهَا دَانِيَةٌ ', 'yang buah-buahannya dekat.', '', 'https://everyayah.com/data/Alafasy_128kbps/069023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:24', 69, 24, 29, 567, 5347, 'كُلُوْا وَاشْرَبُوْا هَنِيْۤـًٔا ۢبِمَآ اَسْلَفْتُمْ فِى الْاَيَّامِ الْخَالِيَةِ ', '(Dikatakan kepada mereka,) “Makan dan minumlah dengan nikmat sebagai balasan amal yang kamu kerjakan pada hari-hari yang telah lalu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/069024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:25', 69, 25, 29, 567, 5348, 'وَاَمَّا مَنْ اُوْتِيَ كِتٰبَهٗ بِشِمَالِهٖ ەۙ فَيَقُوْلُ يٰلَيْتَنِيْ لَمْ اُوْتَ كِتٰبِيَهْۚ', 'Adapun orang yang diberi catatan amalnya di tangan kirinya berkata, “Seandainya saja aku tidak diberi catatan amalku', '', 'https://everyayah.com/data/Alafasy_128kbps/069025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:26', 69, 26, 29, 567, 5349, 'وَلَمْ اَدْرِ مَا حِسَابِيَهْۚ', 'dan tidak mengetahui bagaimana perhitunganku.', '', 'https://everyayah.com/data/Alafasy_128kbps/069026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:27', 69, 27, 29, 567, 5350, 'يٰلَيْتَهَا كَانَتِ الْقَاضِيَةَۚ', 'Seandainya saja ia (kematian) itulah yang menyudahi segala sesuatu.', '', 'https://everyayah.com/data/Alafasy_128kbps/069027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:28', 69, 28, 29, 567, 5351, 'مَآ اَغْنٰى عَنِّيْ مَالِيَهْۚ ', 'Hartaku sama sekali tidak berguna bagiku.', '', 'https://everyayah.com/data/Alafasy_128kbps/069028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:29', 69, 29, 29, 567, 5352, 'هَلَكَ عَنِّيْ سُلْطٰنِيَهْۚ', 'Kekuasaanku telah hilang dariku.”', '', 'https://everyayah.com/data/Alafasy_128kbps/069029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:30', 69, 30, 29, 567, 5353, 'خُذُوْهُ فَغُلُّوْهُۙ', '(Allah berfirman,) “Tangkap dia lalu belenggu tangannya ke lehernya.', '', 'https://everyayah.com/data/Alafasy_128kbps/069030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:31', 69, 31, 29, 567, 5354, 'ثُمَّ الْجَحِيْمَ صَلُّوْهُۙ', 'Kemudian, masukkan dia ke dalam (neraka) Jahim.', '', 'https://everyayah.com/data/Alafasy_128kbps/069031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:32', 69, 32, 29, 567, 5355, 'ثُمَّ فِيْ سِلْسِلَةٍ ذَرْعُهَا سَبْعُوْنَ ذِرَاعًا فَاسْلُكُوْهُۗ', 'Kemudian, belit dia dengan rantai yang panjangnya tujuh puluh hasta.', '', 'https://everyayah.com/data/Alafasy_128kbps/069032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:33', 69, 33, 29, 567, 5356, 'اِنَّهٗ كَانَ لَا يُؤْمِنُ بِاللّٰهِ الْعَظِيْمِۙ', 'Sesungguhnya dia tidak beriman kepada Allah Yang Maha Agung.', '', 'https://everyayah.com/data/Alafasy_128kbps/069033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:34', 69, 34, 29, 567, 5357, 'وَلَا يَحُضُّ عَلٰى طَعَامِ الْمِسْكِيْنِۗ', 'Dia juga tidak mendorong (orang lain) untuk memberi makan orang miskin.', '', 'https://everyayah.com/data/Alafasy_128kbps/069034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:35', 69, 35, 29, 568, 5358, 'فَلَيْسَ لَهُ الْيَوْمَ هٰهُنَا حَمِيْمٌۙ', 'Maka, pada hari ini tidak ada seorang pun teman setia baginya di sini (neraka).', '', 'https://everyayah.com/data/Alafasy_128kbps/069035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:36', 69, 36, 29, 568, 5359, 'وَّلَا طَعَامٌ اِلَّا مِنْ غِسْلِيْنٍۙ', 'Tidak ada makanan (baginya), kecuali dari darah dan nanah.', '', 'https://everyayah.com/data/Alafasy_128kbps/069036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:37', 69, 37, 29, 568, 5360, 'لَّا يَأْكُلُهٗٓ اِلَّا الْخٰطِـُٔوْنَ ࣖ ', 'Tidak ada yang memakannya, kecuali para pendosa.”', '', 'https://everyayah.com/data/Alafasy_128kbps/069037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:38', 69, 38, 29, 568, 5361, 'فَلَآ اُقْسِمُ بِمَا تُبْصِرُوْنَۙ', 'Maka, Aku bersumpah demi apa yang kamu lihat', '', 'https://everyayah.com/data/Alafasy_128kbps/069038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:39', 69, 39, 29, 568, 5362, 'وَمَا لَا تُبْصِرُوْنَۙ', 'dan demi apa yang tidak kamu lihat,', '', 'https://everyayah.com/data/Alafasy_128kbps/069039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:40', 69, 40, 29, 568, 5363, 'اِنَّهٗ لَقَوْلُ رَسُوْلٍ كَرِيْمٍۙ', 'sesungguhnya ia (Al-Qur’an) itu benar-benar wahyu (yang diturunkan kepada) Rasul yang mulia.', '', 'https://everyayah.com/data/Alafasy_128kbps/069040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:41', 69, 41, 29, 568, 5364, 'وَّمَا هُوَ بِقَوْلِ شَاعِرٍۗ قَلِيْلًا مَّا تُؤْمِنُوْنَۙ', 'Ia (Al-Qur’an) bukanlah perkataan seorang penyair. Sedikit sekali kamu beriman (kepadanya).', '', 'https://everyayah.com/data/Alafasy_128kbps/069041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:42', 69, 42, 29, 568, 5365, 'وَلَا بِقَوْلِ كَاهِنٍۗ قَلِيْلًا مَّا تَذَكَّرُوْنَۗ', '(Al-Qur’an) bukan pula perkataan tukang tenung. Sedikit sekali kamu mengambil pelajaran (darinya).', '', 'https://everyayah.com/data/Alafasy_128kbps/069042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:43', 69, 43, 29, 568, 5366, 'تَنْزِيْلٌ مِّنْ رَّبِّ الْعٰلَمِيْنَ ', '(Al-Qur’an itu) diturunkan dari Tuhan semesta alam.', '', 'https://everyayah.com/data/Alafasy_128kbps/069043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:44', 69, 44, 29, 568, 5367, 'وَلَوْ تَقَوَّلَ عَلَيْنَا بَعْضَ الْاَقَاوِيْلِۙ', 'Sekiranya dia (Nabi Muhammad) mengada-adakan sebagian saja perkataan atas (nama) Kami,', '', 'https://everyayah.com/data/Alafasy_128kbps/069044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:45', 69, 45, 29, 568, 5368, 'لَاَخَذْنَا مِنْهُ بِالْيَمِيْنِۙ', 'niscaya Kami benar-benar menyiksanya dengan penuh kekuatan.', '', 'https://everyayah.com/data/Alafasy_128kbps/069045.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:46', 69, 46, 29, 568, 5369, 'ثُمَّ لَقَطَعْنَا مِنْهُ الْوَتِيْنَۖ', 'Kemudian, Kami benar-benar memotong urat nadinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/069046.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:47', 69, 47, 29, 568, 5370, 'فَمَا مِنْكُمْ مِّنْ اَحَدٍ عَنْهُ حٰجِزِيْنَۙ', 'Maka, tidak ada seorang pun dari kamu yang dapat menghalangi (Kami) darinya (pemotongan urat nadi itu).', '', 'https://everyayah.com/data/Alafasy_128kbps/069047.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:48', 69, 48, 29, 568, 5371, 'وَاِنَّهٗ لَتَذْكِرَةٌ لِّلْمُتَّقِيْنَ ', 'Sesungguhnya ia (Al-Qur’an itu) benar-benar suatu pelajaran bagi orang-orang yang bertakwa.', '', 'https://everyayah.com/data/Alafasy_128kbps/069048.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:49', 69, 49, 29, 568, 5372, 'وَاِنَّا لَنَعْلَمُ اَنَّ مِنْكُمْ مُّكَذِّبِيْنَۗ', 'Sesungguhnya Kami benar-benar mengetahui bahwa di antara kamu ada para pendusta.', '', 'https://everyayah.com/data/Alafasy_128kbps/069049.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:50', 69, 50, 29, 568, 5373, 'وَاِنَّهٗ لَحَسْرَةٌ عَلَى الْكٰفِرِيْنَۚ', 'Sesungguhnya ia (pendustaan terhadap Al-Qur’an) benar-benar menjadi penyesalan bagi orang-orang kafir (di akhirat).', '', 'https://everyayah.com/data/Alafasy_128kbps/069050.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:51', 69, 51, 29, 568, 5374, 'وَاِنَّهٗ لَحَقُّ الْيَقِيْنِ ', 'Sesungguhnya ia (Al-Qur’an itu) adalah kebenaran yang meyakinkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/069051.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('69:52', 69, 52, 29, 568, 5375, 'فَسَبِّحْ بِاسْمِ رَبِّكَ الْعَظِيْمِ ࣖ', 'Maka, bertasbihlah dengan (menyebut) nama Tuhanmu Yang Maha Agung.', '', 'https://everyayah.com/data/Alafasy_128kbps/069052.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:1', 70, 1, 29, 568, 5376, 'سَاَلَ سَاۤىِٕلٌۢ بِعَذَابٍ وَّاقِعٍۙ', 'Seseorang (dengan nada mengejek) meminta (didatangkan) azab yang pasti akan terjadi', '', 'https://everyayah.com/data/Alafasy_128kbps/070001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:2', 70, 2, 29, 568, 5377, 'لِّلْكٰفِرِيْنَ لَيْسَ لَهٗ دَافِعٌۙ', 'bagi orang-orang kafir. Tidak seorang pun yang dapat menolaknya (azab)', '', 'https://everyayah.com/data/Alafasy_128kbps/070002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:3', 70, 3, 29, 568, 5378, 'مِّنَ اللّٰهِ ذِى الْمَعَارِجِۗ', 'dari Allah, Pemilik tempat-tempat (untuk) naik.', '', 'https://everyayah.com/data/Alafasy_128kbps/070003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:4', 70, 4, 29, 568, 5379, 'تَعْرُجُ الْمَلٰۤىِٕكَةُ وَالرُّوْحُ اِلَيْهِ فِيْ يَوْمٍ كَانَ مِقْدَارُهٗ خَمْسِيْنَ اَلْفَ سَنَةٍۚ', 'Para malaikat dan Rūḥ (Jibril) naik (menghadap) kepada-Nya dalam sehari yang kadarnya lima puluh ribu tahun.722)', '722) Maksudnya, Jibril dan para malaikat lain butuh waktu satu hari perjalanan untuk menghadap Allah Swt. Satu hari dalam dunia malaikat sama dengan lima puluh ribu tahun dalam dunia manusia.', 'https://everyayah.com/data/Alafasy_128kbps/070004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:5', 70, 5, 29, 568, 5380, 'فَاصْبِرْ صَبْرًا جَمِيْلًا', 'Maka, bersabarlah dengan kesabaran yang baik.', '', 'https://everyayah.com/data/Alafasy_128kbps/070005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:6', 70, 6, 29, 568, 5381, 'اِنَّهُمْ يَرَوْنَهٗ بَعِيْدًاۙ', 'Sesungguhnya mereka memandangnya (siksaan itu) jauh (mustahil terjadi),', '', 'https://everyayah.com/data/Alafasy_128kbps/070006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:7', 70, 7, 29, 568, 5382, 'وَّنَرٰىهُ قَرِيْبًاۗ', 'sedangkan Kami memandangnya dekat (pasti terjadi).', '', 'https://everyayah.com/data/Alafasy_128kbps/070007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:8', 70, 8, 29, 568, 5383, 'يَوْمَ تَكُوْنُ السَّمَاۤءُ كَالْمُهْلِۙ', '(Siksaan itu datang) pada hari (ketika) langit menjadi seperti luluhan perak,', '', 'https://everyayah.com/data/Alafasy_128kbps/070008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:9', 70, 9, 29, 568, 5384, 'وَتَكُوْنُ الْجِبَالُ كَالْعِهْنِۙ', 'gunung-gunung menjadi seperti bulu (yang beterbangan),', '', 'https://everyayah.com/data/Alafasy_128kbps/070009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:10', 70, 10, 29, 568, 5385, 'وَلَا يَسْـَٔلُ حَمِيْمٌ حَمِيْمًاۚ ', 'dan tidak ada seorang pun teman setia yang menanyakan temannya,', '', 'https://everyayah.com/data/Alafasy_128kbps/070010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:11', 70, 11, 29, 569, 5386, 'يُبَصَّرُوْنَهُمْۗ يَوَدُّ الْمُجْرِمُ لَوْ يَفْتَدِيْ مِنْ عَذَابِ يَوْمِىِٕذٍۢ بِبَنِيْهِۙ', '(padahal) mereka saling melihat. Orang yang berbuat durhaka itu menginginkan sekiranya dia dapat menebus (dirinya) dari azab hari itu dengan anak-anaknya,', '', 'https://everyayah.com/data/Alafasy_128kbps/070011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:12', 70, 12, 29, 569, 5387, 'وَصَاحِبَتِهٖ وَاَخِيْهِۙ', 'istrinya, saudaranya,', '', 'https://everyayah.com/data/Alafasy_128kbps/070012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:13', 70, 13, 29, 569, 5388, 'وَفَصِيْلَتِهِ الَّتِيْ تُـْٔوِيْهِۙ', 'keluarga yang melindunginya (di dunia),', '', 'https://everyayah.com/data/Alafasy_128kbps/070013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:14', 70, 14, 29, 569, 5389, 'وَمَنْ فِى الْاَرْضِ جَمِيْعًاۙ ثُمَّ يُنْجِيْهِۙ', 'dan seluruh orang di bumi. Kemudian, (dia mengharapkan) tebusan itu dapat menyelamatkannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/070014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:15', 70, 15, 29, 569, 5390, 'كَلَّاۗ اِنَّهَا لَظٰىۙ', 'Sekali-kali tidak! Sesungguhnya ia (neraka) itu adalah api yang bergejolak', '', 'https://everyayah.com/data/Alafasy_128kbps/070015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:16', 70, 16, 29, 569, 5391, 'نَزَّاعَةً لِّلشَّوٰىۚ', 'yang mengelupaskan kulit kepala,', '', 'https://everyayah.com/data/Alafasy_128kbps/070016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:17', 70, 17, 29, 569, 5392, 'تَدْعُوْا مَنْ اَدْبَرَ وَتَوَلّٰىۙ', 'yang memanggil orang yang berpaling dan menjauh (dari agama),', '', 'https://everyayah.com/data/Alafasy_128kbps/070017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:18', 70, 18, 29, 569, 5393, 'وَجَمَعَ فَاَوْعٰى ', 'serta mengumpulkan (harta benda), lalu menyimpannya.723)', '723) Maksudnya adalah orang-orang yangmenyimpan hartanya, tidak mau mengeluarkan zakat, dan tidak pula menginfakkannya ke jalan yang benar. ', 'https://everyayah.com/data/Alafasy_128kbps/070018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:19', 70, 19, 29, 569, 5394, '۞ اِنَّ الْاِنْسَانَ خُلِقَ هَلُوْعًاۙ', 'Sesungguhnya manusia diciptakan dengan sifat keluh kesah lagi kikir.', '', 'https://everyayah.com/data/Alafasy_128kbps/070019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:20', 70, 20, 29, 569, 5395, 'اِذَا مَسَّهُ الشَّرُّ جَزُوْعًاۙ', 'Apabila ditimpa keburukan (kesusahan), ia berkeluh kesah.', '', 'https://everyayah.com/data/Alafasy_128kbps/070020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:21', 70, 21, 29, 569, 5396, 'وَّاِذَا مَسَّهُ الْخَيْرُ مَنُوْعًاۙ', 'Apabila mendapat kebaikan (harta), ia amat kikir,', '', 'https://everyayah.com/data/Alafasy_128kbps/070021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:22', 70, 22, 29, 569, 5397, 'اِلَّا الْمُصَلِّيْنَۙ', 'kecuali orang-orang yang mengerjakan salat,', '', 'https://everyayah.com/data/Alafasy_128kbps/070022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:23', 70, 23, 29, 569, 5398, 'الَّذِيْنَ هُمْ عَلٰى صَلَاتِهِمْ دَاۤىِٕمُوْنَۖ', 'yang selalu setia mengerjakan salatnya,', '', 'https://everyayah.com/data/Alafasy_128kbps/070023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:24', 70, 24, 29, 569, 5399, 'وَالَّذِيْنَ فِيْٓ اَمْوَالِهِمْ حَقٌّ مَّعْلُوْمٌۖ', 'yang di dalam hartanya ada bagian tertentu', '', 'https://everyayah.com/data/Alafasy_128kbps/070024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:25', 70, 25, 29, 569, 5400, 'لِّلسَّاۤىِٕلِ وَالْمَحْرُوْمِۖ', 'untuk orang (miskin) yang meminta-minta dan orang (miskin) yang menahan diri dari meminta-minta,', '', 'https://everyayah.com/data/Alafasy_128kbps/070025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:26', 70, 26, 29, 569, 5401, 'وَالَّذِيْنَ يُصَدِّقُوْنَ بِيَوْمِ الدِّيْنِۖ', 'yang memercayai hari Pembalasan,', '', 'https://everyayah.com/data/Alafasy_128kbps/070026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:27', 70, 27, 29, 569, 5402, 'وَالَّذِيْنَ هُمْ مِّنْ عَذَابِ رَبِّهِمْ مُّشْفِقُوْنَۚ', 'dan yang takut terhadap azab Tuhannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/070027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:28', 70, 28, 29, 569, 5403, 'اِنَّ عَذَابَ رَبِّهِمْ غَيْرُ مَأْمُوْنٍۖ', 'Sesungguhnya tidak ada orang yang merasa aman dari azab Tuhan mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/070028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:29', 70, 29, 29, 569, 5404, 'وَّالَّذِيْنَ هُمْ لِفُرُوْجِهِمْ حٰفِظُوْنَۙ', '(Termasuk orang yang selamat dari azab adalah) orang-orang yang menjaga kemaluannya,', '', 'https://everyayah.com/data/Alafasy_128kbps/070029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:30', 70, 30, 29, 569, 5405, 'اِلَّا عَلٰٓى اَزْوَاجِهِمْ اَوْ مَا مَلَكَتْ اَيْمَانُهُمْ فَاِنَّهُمْ غَيْرُ مَلُوْمِيْنَۚ', 'kecuali terhadap istri-istri mereka atau hamba sahaya yang mereka miliki.724) Sesungguhnya mereka tidak tercela (karena menggaulinya).', '724) Lihat catatan kaki surah al-Mu’minūn (23): 6.', 'https://everyayah.com/data/Alafasy_128kbps/070030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:31', 70, 31, 29, 569, 5406, 'فَمَنِ ابْتَغٰى وَرَاۤءَ ذٰلِكَ فَاُولٰۤىِٕكَ هُمُ الْعَادُوْنَۚ', 'Maka, siapa yang mencari (pelampiasan syahwat) selain itu, mereka itulah orang-orang yang melampaui batas.', '', 'https://everyayah.com/data/Alafasy_128kbps/070031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:32', 70, 32, 29, 569, 5407, 'وَالَّذِيْنَ هُمْ لِاَمٰنٰتِهِمْ وَعَهْدِهِمْ رٰعُوْنَۖ', '(Termasuk orang yang selamat dari azab adalah) orang-orang yang memelihara amanat dan janji mereka,', '', 'https://everyayah.com/data/Alafasy_128kbps/070032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:33', 70, 33, 29, 569, 5408, 'وَالَّذِيْنَ هُمْ بِشَهٰدٰتِهِمْ قَاۤىِٕمُوْنَۖ', 'yang memberikan kesaksiannya (secara benar),', '', 'https://everyayah.com/data/Alafasy_128kbps/070033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:34', 70, 34, 29, 569, 5409, 'وَالَّذِيْنَ هُمْ عَلٰى صَلَاتِهِمْ يُحَافِظُوْنَۖ', 'dan yang memelihara salatnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/070034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:35', 70, 35, 29, 569, 5410, 'اُولٰۤىِٕكَ فِيْ جَنّٰتٍ مُّكْرَمُوْنَ ۗ ࣖ', 'Mereka itu (berada) di surga lagi dimuliakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/070035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:36', 70, 36, 29, 569, 5411, 'فَمَالِ الَّذِيْنَ كَفَرُوْا قِبَلَكَ مُهْطِعِيْنَۙ', 'Mengapa orang-orang kafir itu bersegera datang ke arahmu (Nabi Muhammad)', '', 'https://everyayah.com/data/Alafasy_128kbps/070036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:37', 70, 37, 29, 569, 5412, 'عَنِ الْيَمِيْنِ وَعَنِ الشِّمَالِ عِزِيْنَ ', 'dari kanan dan dari kiri dengan berkelompok-kelompok?725)', '725) Menurut sebagian mufasir, padasuatu hari orang-orang musyrik berkerumun di hadapan Rasulullah saw. sambil mengejek dan mengatakan, “Jika orang-orang mukmin benar-benar akan masuk surga sebagaimana kata Muhammad, kitalah yang akan masuk terlebih dahulu.” Maka, turunlah ayat 38.', 'https://everyayah.com/data/Alafasy_128kbps/070037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:38', 70, 38, 29, 569, 5413, 'اَيَطْمَعُ كُلُّ امْرِئٍ مِّنْهُمْ اَنْ يُّدْخَلَ جَنَّةَ نَعِيْمٍۙ', 'Apakah setiap orang dari mereka (orang-orang kafir itu) ingin dimasukkan ke dalam surga yang penuh kenikmatan?', '', 'https://everyayah.com/data/Alafasy_128kbps/070038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:39', 70, 39, 29, 569, 5414, 'كَلَّاۗ اِنَّا خَلَقْنٰهُمْ مِّمَّا يَعْلَمُوْنَ ', 'Sekali-kali tidak! Sesungguhnya Kami menciptakan mereka dari apa yang mereka ketahui (air mani).726)', '726) Orang-orang kafir itu mengetahui bahwa mereka diciptakan oleh Allah dari air mani untuk beriman dan bertakwa kepada-Nya seperti manusia lainnya. Jadi, jika tidak beriman dan bertakwa, mereka tidak berhak masuk surga.', 'https://everyayah.com/data/Alafasy_128kbps/070039.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:40', 70, 40, 29, 570, 5415, 'فَلَآ اُقْسِمُ بِرَبِّ الْمَشٰرِقِ وَالْمَغٰرِبِ اِنَّا لَقٰدِرُوْنَۙ', 'Maka, Aku bersumpah dengan Tuhan yang mengatur tempat-tempat terbit dan terbenamnya (matahari, bulan, dan bintang), sesungguhnya Kami benar-benar Maha Kuasa', '', 'https://everyayah.com/data/Alafasy_128kbps/070040.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:41', 70, 41, 29, 570, 5416, 'عَلٰٓى اَنْ نُّبَدِّلَ خَيْرًا مِّنْهُمْۙ وَمَا نَحْنُ بِمَسْبُوْقِيْنَ ', 'untuk mengganti (mereka) dengan (kaum) yang lebih baik daripada mereka. Kami sekali-kali tidak dapat dikalahkan.', '', 'https://everyayah.com/data/Alafasy_128kbps/070041.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:42', 70, 42, 29, 570, 5417, 'فَذَرْهُمْ يَخُوْضُوْا وَيَلْعَبُوْا حَتّٰى يُلٰقُوْا يَوْمَهُمُ الَّذِيْ يُوْعَدُوْنَۙ', 'Maka, biarkanlah mereka tenggelam (dalam kesesatan) dan bermain-main (di dunia) sampai mereka menjumpai hari yang dijanjikan kepada mereka,', '', 'https://everyayah.com/data/Alafasy_128kbps/070042.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:43', 70, 43, 29, 570, 5418, 'يَوْمَ يَخْرُجُوْنَ مِنَ الْاَجْدَاثِ سِرَاعًا كَاَنَّهُمْ اِلٰى نُصُبٍ يُّوْفِضُوْنَۙ', '(yaitu) pada hari ketika mereka keluar dari kubur dengan cepat seperti ketika mereka pergi dengan segera menuju berhala-berhala (sewaktu di dunia).', '', 'https://everyayah.com/data/Alafasy_128kbps/070043.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('70:44', 70, 44, 29, 570, 5419, 'خَاشِعَةً اَبْصَارُهُمْ تَرْهَقُهُمْ ذِلَّةٌ  ۗذٰلِكَ الْيَوْمُ الَّذِيْ كَانُوْا يُوْعَدُوْنَ ࣖ ', 'Pandangan mereka tertunduk (serta) diliputi kehinaan. Itulah hari yang diancamkan kepada mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/070044.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:1', 71, 1, 29, 570, 5420, 'اِنَّآ اَرْسَلْنَا نُوْحًا اِلٰى قَوْمِهٖٓ اَنْ اَنْذِرْ قَوْمَكَ مِنْ قَبْلِ اَنْ يَّأْتِيَهُمْ عَذَابٌ اَلِيْمٌ ', 'Sesungguhnya Kami telah mengutus Nuh kepada kaumnya (dengan perintah), “Berilah peringatan kepada kaummu sebelum datang azab yang pedih kepadanya!”', '', 'https://everyayah.com/data/Alafasy_128kbps/071001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:2', 71, 2, 29, 570, 5421, 'قَالَ يٰقَوْمِ اِنِّيْ لَكُمْ نَذِيْرٌ مُّبِيْنٌۙ', 'Dia (Nuh) berkata, “Wahai kaumku, sesungguhnya aku ini adalah seorang pemberi peringatan yang menjelaskan kepadamu,', '', 'https://everyayah.com/data/Alafasy_128kbps/071002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:3', 71, 3, 29, 570, 5422, 'اَنِ اعْبُدُوا اللّٰهَ وَاتَّقُوْهُ وَاَطِيْعُوْنِۙ ', '(yaitu) sembahlah Allah, bertakwalah kepada-Nya, dan taatlah kepadaku,', '', 'https://everyayah.com/data/Alafasy_128kbps/071003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:4', 71, 4, 29, 570, 5423, 'يَغْفِرْ لَكُمْ مِّنْ ذُنُوْبِكُمْ وَيُؤَخِّرْكُمْ اِلٰٓى اَجَلٍ مُّسَمًّىۗ اِنَّ اَجَلَ اللّٰهِ اِذَا جَاۤءَ لَا يُؤَخَّرُۘ لَوْ كُنْتُمْ تَعْلَمُوْنَ ', 'niscaya Dia akan mengampuni sebagian dosa-dosamu dan menangguhkanmu (memanjangkan umurmu) sampai pada batas waktu yang ditentukan. Sesungguhnya ketetapan Allah itu, apabila telah datang, tidak dapat ditunda. Seandainya kamu mengetahui(-nya).”', '', 'https://everyayah.com/data/Alafasy_128kbps/071004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:5', 71, 5, 29, 570, 5424, 'قَالَ رَبِّ اِنِّيْ دَعَوْتُ قَوْمِيْ لَيْلًا وَّنَهَارًاۙ', 'Dia (Nuh) berkata, “Ya Tuhanku, sesungguhnya aku telah menyeru kaumku siang dan malam,', '', 'https://everyayah.com/data/Alafasy_128kbps/071005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:6', 71, 6, 29, 570, 5425, 'فَلَمْ يَزِدْهُمْ دُعَاۤءِيْٓ اِلَّا فِرَارًا ', 'tetapi seruanku itu tidak menambah (iman) mereka, melainkan mereka (makin) lari (dari kebenaran).', '', 'https://everyayah.com/data/Alafasy_128kbps/071006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:7', 71, 7, 29, 570, 5426, 'وَاِنِّيْ كُلَّمَا دَعَوْتُهُمْ لِتَغْفِرَ لَهُمْ جَعَلُوْٓا اَصَابِعَهُمْ فِيْٓ اٰذَانِهِمْ وَاسْتَغْشَوْا ثِيَابَهُمْ وَاَصَرُّوْا وَاسْتَكْبَرُوا اسْتِكْبَارًاۚ ', 'Sesungguhnya setiap kali aku menyeru mereka (untuk beriman) agar Engkau mengampuni mereka, mereka memasukkan anak jarinya ke telinganya dan menutupkan bajunya (ke wajahnya). Mereka pun tetap (mengingkari) dan sangat menyombongkan diri.', '', 'https://everyayah.com/data/Alafasy_128kbps/071007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:8', 71, 8, 29, 570, 5427, 'ثُمَّ اِنِّيْ دَعَوْتُهُمْ جِهَارًاۙ', 'Kemudian, sesungguhnya aku menyeru mereka dengan cara terang-terangan.727)', '727) Dakwah ini dilakukan setelah dakwah dengan cara diam-diam tidak berhasil.', 'https://everyayah.com/data/Alafasy_128kbps/071008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:9', 71, 9, 29, 570, 5428, 'ثُمَّ اِنِّيْٓ اَعْلَنْتُ لَهُمْ وَاَسْرَرْتُ لَهُمْ اِسْرَارًاۙ', 'Lalu, aku menyeru mereka secara terbuka dan diam-diam.728)', '728) Setelah gagalnya dakwah secara diam-diam dan dakwah secara terang-terangan, Nabi Nuh a.s. melakukan keduanya sekaligus.', 'https://everyayah.com/data/Alafasy_128kbps/071009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:10', 71, 10, 29, 570, 5429, 'فَقُلْتُ اسْتَغْفِرُوْا رَبَّكُمْ اِنَّهٗ كَانَ غَفَّارًاۙ', 'Lalu, aku berkata (kepada mereka), “Mohonlah ampun kepada Tuhanmu. Sesungguhnya Dia Maha Pengampun.', '', 'https://everyayah.com/data/Alafasy_128kbps/071010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:11', 71, 11, 29, 571, 5430, 'يُّرْسِلِ السَّمَاۤءَ عَلَيْكُمْ مِّدْرَارًاۙ', '(Jika kamu memohon ampun,) niscaya Dia akan menurunkan hujan yang lebat dari langit kepadamu,', '', 'https://everyayah.com/data/Alafasy_128kbps/071011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:12', 71, 12, 29, 571, 5431, 'وَّيُمْدِدْكُمْ بِاَمْوَالٍ وَّبَنِيْنَ وَيَجْعَلْ لَّكُمْ جَنّٰتٍ وَّيَجْعَلْ لَّكُمْ اَنْهٰرًاۗ', 'memperbanyak harta dan anak-anakmu, serta mengadakan kebun-kebun dan sungai-sungai untukmu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/071012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:13', 71, 13, 29, 571, 5432, 'مَا لَكُمْ لَا تَرْجُوْنَ لِلّٰهِ وَقَارًاۚ', 'Mengapa kamu tidak takut akan kebesaran Allah?', '', 'https://everyayah.com/data/Alafasy_128kbps/071013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:14', 71, 14, 29, 571, 5433, 'وَقَدْ خَلَقَكُمْ اَطْوَارًا ', 'Padahal, sungguh, Dia telah menciptakanmu dalam beberapa tahapan (penciptaan).729)', '729) Lihat surah al-Mu’minūn (23): 12‒14.', 'https://everyayah.com/data/Alafasy_128kbps/071014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:15', 71, 15, 29, 571, 5434, 'اَلَمْ تَرَوْا كَيْفَ خَلَقَ اللّٰهُ سَبْعَ سَمٰوٰتٍ طِبَاقًاۙ', 'Tidakkah kamu memperhatikan bagaimana Allah telah menciptakan tujuh langit berlapis-lapis?', '', 'https://everyayah.com/data/Alafasy_128kbps/071015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:16', 71, 16, 29, 571, 5435, 'وَّجَعَلَ الْقَمَرَ فِيْهِنَّ نُوْرًا وَّجَعَلَ الشَّمْسَ سِرَاجًا ', 'Di sana Dia menjadikan bulan bercahaya dan matahari sebagai pelita (yang cemerlang).', '', 'https://everyayah.com/data/Alafasy_128kbps/071016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:17', 71, 17, 29, 571, 5436, 'وَاللّٰهُ اَنْۢبَتَكُمْ مِّنَ الْاَرْضِ نَبَاتًاۙ', 'Allah benar-benar menciptakanmu dari tanah.', '', 'https://everyayah.com/data/Alafasy_128kbps/071017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:18', 71, 18, 29, 571, 5437, 'ثُمَّ يُعِيْدُكُمْ فِيْهَا وَيُخْرِجُكُمْ اِخْرَاجًا ', 'Kemudian, dia akan mengembalikanmu ke dalamnya (tanah) dan mengeluarkanmu (pada hari Kiamat) dengan pasti. ', '', 'https://everyayah.com/data/Alafasy_128kbps/071018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:19', 71, 19, 29, 571, 5438, 'وَاللّٰهُ جَعَلَ لَكُمُ الْاَرْضَ بِسَاطًاۙ', 'Allah menjadikan bumi untukmu sebagai hamparan', '', 'https://everyayah.com/data/Alafasy_128kbps/071019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:20', 71, 20, 29, 571, 5439, 'لِّتَسْلُكُوْا مِنْهَا سُبُلًا فِجَاجًا ࣖ ', 'agar kamu dapat pergi dengan leluasa di jalan-jalan yang luas.', '', 'https://everyayah.com/data/Alafasy_128kbps/071020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:21', 71, 21, 29, 571, 5440, 'قَالَ نُوْحٌ رَّبِّ اِنَّهُمْ عَصَوْنِيْ وَاتَّبَعُوْا مَنْ لَّمْ يَزِدْهُ مَالُهٗ وَوَلَدُهٗٓ اِلَّا خَسَارًاۚ ', 'Nuh berkata, “Ya Tuhanku, sesungguhnya mereka durhaka kepadaku dan mengikuti orang-orang yang harta dan anak-anaknya hanya menambah kerugian baginya.', '', 'https://everyayah.com/data/Alafasy_128kbps/071021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:22', 71, 22, 29, 571, 5441, 'وَمَكَرُوْا مَكْرًا كُبَّارًاۚ', 'Mereka pun melakukan tipu daya yang sangat besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/071022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:23', 71, 23, 29, 571, 5442, 'وَقَالُوْا لَا تَذَرُنَّ اٰلِهَتَكُمْ وَلَا تَذَرُنَّ وَدًّا وَّلَا سُوَاعًا ەۙ وَّلَا يَغُوْثَ وَيَعُوْقَ وَنَسْرًاۚ', 'Mereka berkata, ‘Jangan sekali-kali kamu meninggalkan tuhan-tuhanmu dan jangan pula sekali-kali kamu meninggalkan Wadd, Suwā‘, Yagūṡ, Ya‘ūq, dan Nasr.’730)', '730) Kelimanya adalah nama-nama berhala terbesar pada kabilah-kabilah kaum Nabi Nuh a.s. yang semula merupakan nama-nama orang saleh.', 'https://everyayah.com/data/Alafasy_128kbps/071023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:24', 71, 24, 29, 571, 5443, 'وَقَدْ اَضَلُّوْا كَثِيْرًا ەۚ وَلَا تَزِدِ الظّٰلِمِيْنَ اِلَّا ضَلٰلًا', 'Sungguh, mereka telah menyesatkan banyak orang. Janganlah Engkau tambahkan bagi orang-orang zalim itu selain kesesatan.”', '', 'https://everyayah.com/data/Alafasy_128kbps/071024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:25', 71, 25, 29, 571, 5444, 'مِمَّا خَطِيْۤـٰٔتِهِمْ اُغْرِقُوْا فَاُدْخِلُوْا نَارًا ەۙ فَلَمْ يَجِدُوْا لَهُمْ مِّنْ دُوْنِ اللّٰهِ اَنْصَارًا', 'Disebabkan kesalahan-kesalahan mereka, mereka ditenggelamkan, lalu dimasukkan ke neraka. Mereka tidak mendapat penolong selain Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/071025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:26', 71, 26, 29, 571, 5445, 'وَقَالَ نُوْحٌ رَّبِّ لَا تَذَرْ عَلَى الْاَرْضِ مِنَ الْكٰفِرِيْنَ دَيَّارًا ', 'Nuh berkata, “Ya Tuhanku, janganlah Engkau biarkan seorang pun di antara orang-orang kafir itu tinggal di atas bumi.', '', 'https://everyayah.com/data/Alafasy_128kbps/071026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:27', 71, 27, 29, 571, 5446, 'اِنَّكَ اِنْ تَذَرْهُمْ يُضِلُّوْا عِبَادَكَ وَلَا يَلِدُوْٓا اِلَّا فَاجِرًا كَفَّارًا ', 'Sesungguhnya jika Engkau biarkan mereka tinggal, niscaya mereka akan menyesatkan hamba-hamba-Mu. Mereka pun hanya akan melahirkan anak-anak yang jahat dan tidak tahu bersyukur.', '', 'https://everyayah.com/data/Alafasy_128kbps/071027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('71:28', 71, 28, 29, 571, 5447, 'رَبِّ اغْفِرْ لِيْ وَلِوَالِدَيَّ وَلِمَنْ دَخَلَ بَيْتِيَ مُؤْمِنًا وَّلِلْمُؤْمِنِيْنَ وَالْمُؤْمِنٰتِۗ وَلَا تَزِدِ الظّٰلِمِيْنَ اِلَّا تَبَارًا ࣖ', 'Ya Tuhanku, ampunilah aku, ibu bapakku, dan siapa pun yang memasuki rumahku dengan beriman dan semua orang yang beriman laki-laki dan perempuan. Janganlah Engkau tambahkan bagi orang-orang zalim itu selain kehancuran.”', '', 'https://everyayah.com/data/Alafasy_128kbps/071028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:1', 72, 1, 29, 572, 5448, 'قُلْ اُوْحِيَ اِلَيَّ اَنَّهُ اسْتَمَعَ نَفَرٌ مِّنَ الْجِنِّ فَقَالُوْٓا اِنَّا سَمِعْنَا قُرْاٰنًا عَجَبًاۙ', 'Katakanlah (Nabi Muhammad), “Telah diwahyukan kepadaku bahwa sekumpulan jin telah mendengarkan (Al-Qur’an yang kubaca).” Lalu, mereka berkata, “Kami telah mendengarkan bacaan yang menakjubkan,', '', 'https://everyayah.com/data/Alafasy_128kbps/072001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:2', 72, 2, 29, 572, 5449, 'يَّهْدِيْٓ اِلَى الرُّشْدِ فَاٰمَنَّا بِهٖۗ وَلَنْ نُّشْرِكَ بِرَبِّنَآ اَحَدًاۖ', 'yang memberi petunjuk pada kebenaran, sehingga kami pun beriman padanya dan tidak akan mempersekutukan sesuatu pun dengan Tuhan kami. ', '', 'https://everyayah.com/data/Alafasy_128kbps/072002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:3', 72, 3, 29, 572, 5450, 'وَّاَنَّهٗ تَعٰلٰى جَدُّ رَبِّنَا مَا اتَّخَذَ صَاحِبَةً وَّلَا وَلَدًاۖ', 'Sesungguhnya Maha Tinggi keagungan Tuhan kami. Dia tidak beristri dan tidak (pula) beranak.', '', 'https://everyayah.com/data/Alafasy_128kbps/072003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:4', 72, 4, 29, 572, 5451, 'وَّاَنَّهٗ كَانَ يَقُوْلُ سَفِيْهُنَا عَلَى اللّٰهِ شَطَطًاۖ', 'Sesungguhnya orang yang bodoh di antara kami selalu mengucapkan (perkataan) yang melampaui batas terhadap Allah.', '', 'https://everyayah.com/data/Alafasy_128kbps/072004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:5', 72, 5, 29, 572, 5452, 'وَّاَنَّا ظَنَنَّآ اَنْ لَّنْ تَقُوْلَ الْاِنْسُ وَالْجِنُّ عَلَى اللّٰهِ كَذِبًاۙ', 'Sesungguhnya kami mengira bahwa manusia dan jin itu tidak akan mengatakan perkataan yang dusta terhadap Allah.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/072005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:6', 72, 6, 29, 572, 5453, 'وَّاَنَّهٗ كَانَ رِجَالٌ مِّنَ الْاِنْسِ يَعُوْذُوْنَ بِرِجَالٍ مِّنَ الْجِنِّ فَزَادُوْهُمْ رَهَقًاۖ', 'Sesungguhnya ada beberapa orang laki-laki dari (kalangan) manusia yang meminta perlindungan kepada beberapa laki-laki dari (kalangan) jin sehingga mereka (jin) menjadikan mereka (manusia) bertambah sesat.', '', 'https://everyayah.com/data/Alafasy_128kbps/072006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:7', 72, 7, 29, 572, 5454, 'وَّاَنَّهُمْ ظَنُّوْا كَمَا ظَنَنْتُمْ اَنْ لَّنْ يَّبْعَثَ اللّٰهُ اَحَدًاۖ', 'Sesungguhnya mereka (jin) mengira sebagaimana kamu (orang musyrik Makkah) mengira bahwa Allah tidak akan membangkitkan kembali siapa pun (pada hari Kiamat). ', '', 'https://everyayah.com/data/Alafasy_128kbps/072007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:8', 72, 8, 29, 572, 5455, 'وَّاَنَّا لَمَسْنَا السَّمَاۤءَ فَوَجَدْنٰهَا مُلِئَتْ حَرَسًا شَدِيْدًا وَّشُهُبًاۖ', '(Jin berkata lagi,) “Sesungguhnya kami (jin) telah mencoba mengetahui (rahasia) langit. Maka, kami mendapatinya penuh dengan penjagaan yang kuat dan panah-panah api.', '', 'https://everyayah.com/data/Alafasy_128kbps/072008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:9', 72, 9, 29, 572, 5456, 'وَّاَنَّا كُنَّا نَقْعُدُ مِنْهَا مَقَاعِدَ لِلسَّمْعِۗ فَمَنْ يَّسْتَمِعِ الْاٰنَ يَجِدْ لَهٗ شِهَابًا رَّصَدًاۖ', 'Sesungguhnya kami (jin) dahulu selalu menduduki beberapa tempat (di langit) untuk mencuri dengar (berita-beritanya). Akan tetapi, sekarang731) siapa yang (mencoba) mencuri dengar pasti akan menjumpai panah api yang mengintai (untuk membakarnya).', '731) Yang dimaksud dengan sekarang adalah waktu setelah Nabi Muhammad saw. diutus menjadi rasul.', 'https://everyayah.com/data/Alafasy_128kbps/072009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:10', 72, 10, 29, 572, 5457, 'وَّاَنَّا لَا نَدْرِيْٓ اَشَرٌّ اُرِيْدَ بِمَنْ فِى الْاَرْضِ اَمْ اَرَادَ بِهِمْ رَبُّهُمْ رَشَدًاۙ', 'Sesungguhnya kami tidak mengetahui apakah keburukan yang dikehendaki terhadap siapa yang di bumi ataukah Tuhan mereka menghendaki kebaikan terhadap mereka. ', '', 'https://everyayah.com/data/Alafasy_128kbps/072010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:11', 72, 11, 29, 572, 5458, 'وَّاَنَّا مِنَّا الصّٰلِحُوْنَ وَمِنَّا دُوْنَ ذٰلِكَۗ  كُنَّا طَرَاۤىِٕقَ قِدَدًاۙ', 'Sesungguhnya di antara kami ada yang saleh dan di antara kami ada (pula) yang tidak demikian halnya. Kami menempuh jalan yang berbeda-beda.', '', 'https://everyayah.com/data/Alafasy_128kbps/072011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:12', 72, 12, 29, 572, 5459, 'وَّاَنَّا ظَنَنَّآ اَنْ لَّنْ نُّعْجِزَ اللّٰهَ فِى الْاَرْضِ وَلَنْ نُّعْجِزَهٗ هَرَبًاۖ', 'Sesungguhnya kami yakin bahwa kami tidak akan mampu melepaskan diri (dari kekuasaan) Allah di bumi dan tidak (pula) dapat lari melepaskan diri (dari)-Nya.', '', 'https://everyayah.com/data/Alafasy_128kbps/072012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:13', 72, 13, 29, 572, 5460, 'وَّاَنَّا لَمَّا سَمِعْنَا الْهُدٰىٓ اٰمَنَّا بِهٖۗ فَمَنْ يُّؤْمِنْۢ بِرَبِّهٖ فَلَا يَخَافُ بَخْسًا وَّلَا رَهَقًاۖ', 'Sesungguhnya ketika mendengar petunjuk (Al-Qur’an), kami pun beriman kepadanya. Maka, siapa yang beriman kepada Tuhannya tidak (perlu) takut akan pengurangan (pahala amalnya) dan tidak (takut pula) akan kesulitan (akibat penambahan dosa).', '', 'https://everyayah.com/data/Alafasy_128kbps/072013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:14', 72, 14, 29, 573, 5461, 'وَّاَنَّا مِنَّا الْمُسْلِمُوْنَ وَمِنَّا الْقٰسِطُوْنَۗ فَمَنْ اَسْلَمَ فَاُولٰۤىِٕكَ تَحَرَّوْا رَشَدًا ', 'Sesungguhnya di antara kami ada yang muslim dan ada (pula) yang menyimpang dari kebenaran. Siapa yang (memeluk) Islam telah memilih jalan yang benar.', '', 'https://everyayah.com/data/Alafasy_128kbps/072014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:15', 72, 15, 29, 573, 5462, 'وَاَمَّا الْقٰسِطُوْنَ فَكَانُوْا لِجَهَنَّمَ حَطَبًاۙ', 'Adapun para penyimpang dari kebenaran menjadi bahan bakar (neraka) Jahanam.”', '', 'https://everyayah.com/data/Alafasy_128kbps/072015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:16', 72, 16, 29, 573, 5463, 'وَّاَنْ لَّوِ اسْتَقَامُوْا عَلَى الطَّرِيْقَةِ لَاَسْقَيْنٰهُمْ مَّاۤءً غَدَقًاۙ', 'Seandainya mereka tetap berjalan lurus di atas jalan itu (agama Islam), niscaya Kami akan mencurahkan air yang banyak (rezeki yang cukup).', '', 'https://everyayah.com/data/Alafasy_128kbps/072016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:17', 72, 17, 29, 573, 5464, 'لِّنَفْتِنَهُمْ فِيْهِۗ وَمَنْ يُّعْرِضْ عَنْ ذِكْرِ رَبِّهٖ يَسْلُكْهُ عَذَابًا صَعَدًاۙ', 'Dengan (cara) itu Kami hendak menguji mereka. Siapa yang berpaling dari peringatan Tuhannya niscaya akan dimasukkan-Nya ke dalam azab yang sangat berat. ', '', 'https://everyayah.com/data/Alafasy_128kbps/072017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:18', 72, 18, 29, 573, 5465, 'وَّاَنَّ الْمَسٰجِدَ لِلّٰهِ فَلَا تَدْعُوْا مَعَ اللّٰهِ اَحَدًاۖ', 'Sesungguhnya masjid-masjid itu milik Allah. Maka, janganlah menyembah apa pun bersamaan dengan (menyembah) Allah. ', '', 'https://everyayah.com/data/Alafasy_128kbps/072018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:19', 72, 19, 29, 573, 5466, 'وَّاَنَّهٗ لَمَّا قَامَ عَبْدُ اللّٰهِ يَدْعُوْهُ كَادُوْا يَكُوْنُوْنَ عَلَيْهِ لِبَدًاۗ  ࣖ', 'Sesungguhnya ketika hamba Allah (Nabi Muhammad) berdiri menyembah-Nya (melaksanakan salat), mereka (jin-jin) itu berdesakan mengerumuninya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/072019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:20', 72, 20, 29, 573, 5467, 'قُلْ اِنَّمَآ اَدْعُوْا رَبِّيْ وَلَآ اُشْرِكُ بِهٖٓ اَحَدًا ', 'Katakanlah (Nabi Muhammad), “Sesungguhnya aku hanya menyembah Tuhanku dan aku tidak mempersekutukan-Nya dengan apa pun.”', '', 'https://everyayah.com/data/Alafasy_128kbps/072020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:21', 72, 21, 29, 573, 5468, 'قُلْ اِنِّيْ لَآ اَمْلِكُ لَكُمْ ضَرًّا وَّلَا رَشَدًا ', 'Katakanlah, “Sesungguhnya aku tidak mampu (menolak) mudarat dan tidak (pula mampu mendatangkan) kebaikan kepadamu.”', '', 'https://everyayah.com/data/Alafasy_128kbps/072021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:22', 72, 22, 29, 573, 5469, 'قُلْ اِنِّيْ لَنْ يُّجِيْرَنِيْ مِنَ اللّٰهِ اَحَدٌ ەۙ وَّلَنْ اَجِدَ مِنْ دُوْنِهٖ مُلْتَحَدًا ۙ', 'Katakanlah, “Sesungguhnya tidak ada seorang pun yang dapat melindungiku dari (azab) Allah dan aku tidak akan memperoleh tempat berlindung selain-Nya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/072022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:23', 72, 23, 29, 573, 5470, 'اِلَّا بَلٰغًا مِّنَ اللّٰهِ وَرِسٰلٰتِهٖۗ وَمَنْ يَّعْصِ اللّٰهَ وَرَسُوْلَهٗ فَاِنَّ لَهٗ نَارَ جَهَنَّمَ خٰلِدِيْنَ فِيْهَآ اَبَدًاۗ', '(Yang aku mampu lakukan) hanyalah menyampaikan (peringatan) dari Allah dan risalah-Nya. Siapa yang mendurhakai Allah dan Rasul-Nya sesungguhnya akan mendapat (azab) neraka Jahanam. Mereka kekal di dalamnya selama-lamanya.”', '', 'https://everyayah.com/data/Alafasy_128kbps/072023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:24', 72, 24, 29, 573, 5471, 'حَتّٰىٓ اِذَا رَاَوْا مَا يُوْعَدُوْنَ فَسَيَعْلَمُوْنَ مَنْ اَضْعَفُ نَاصِرًا وَّاَقَلُّ عَدَدًاۗ', 'Dengan demikian, apabila melihat (azab) yang diancamkan kepadanya, mereka akan mengetahui siapakah yang lebih lemah penolongnya dan lebih sedikit jumlahnya. ', '', 'https://everyayah.com/data/Alafasy_128kbps/072024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:25', 72, 25, 29, 573, 5472, 'قُلْ اِنْ اَدْرِيْٓ اَقَرِيْبٌ مَّا تُوْعَدُوْنَ اَمْ يَجْعَلُ لَهٗ رَبِّيْٓ اَمَدًا ', 'Katakanlah (Nabi Muhammad), “Aku tidak mengetahui apakah (azab) yang diancamkan kepadamu itu sudah dekat atau Tuhanku menjadikan waktunya masih lama.”', '', 'https://everyayah.com/data/Alafasy_128kbps/072025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:26', 72, 26, 29, 573, 5473, 'عٰلِمُ الْغَيْبِ فَلَا يُظْهِرُ عَلٰى غَيْبِهٖٓ اَحَدًاۙ', 'Dia mengetahui yang gaib. Lalu, Dia tidak memperlihatkan yang gaib itu kepada siapa pun,', '', 'https://everyayah.com/data/Alafasy_128kbps/072026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:27', 72, 27, 29, 573, 5474, 'اِلَّا مَنِ ارْتَضٰى مِنْ رَّسُوْلٍ فَاِنَّهٗ يَسْلُكُ مِنْۢ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهٖ رَصَدًاۙ', 'kecuali kepada rasul yang diridai-Nya. Sesungguhnya Dia menempatkan penjaga-penjaga (malaikat) di depan dan di belakangnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/072027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('72:28', 72, 28, 29, 573, 5475, 'لِّيَعْلَمَ اَنْ قَدْ اَبْلَغُوْا رِسٰلٰتِ رَبِّهِمْ وَاَحَاطَ بِمَا لَدَيْهِمْ وَاَحْصٰى كُلَّ شَيْءٍ عَدَدًا ࣖ', '(Yang demikian itu) agar Dia mengetahui bahwa (rasul-rasul itu) benar-benar telah menyampaikan risalah-risalah Tuhannya, sedangkan (ilmu-Nya) meliputi apa yang ada pada mereka. Dia menghitung segala sesuatu satu per satu.', '', 'https://everyayah.com/data/Alafasy_128kbps/072028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:1', 73, 1, 29, 574, 5476, 'يٰٓاَيُّهَا الْمُزَّمِّلُۙ', 'Wahai orang yang berkelumun (Nabi Muhammad),', '', 'https://everyayah.com/data/Alafasy_128kbps/073001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:2', 73, 2, 29, 574, 5477, 'قُمِ الَّيْلَ اِلَّا قَلِيْلًاۙ', 'bangunlah (untuk salat) pada malam hari, kecuali sebagian kecil,732)', '732) Salat malam hukumnya wajib sebelum ayat ke-20 surah ini diturunkan. Setelah itu, hukumnya menjadi sunah.', 'https://everyayah.com/data/Alafasy_128kbps/073002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:3', 73, 3, 29, 574, 5478, 'نِّصْفَهٗٓ اَوِ انْقُصْ مِنْهُ قَلِيْلًاۙ', '(yaitu) seperduanya, kurang sedikit dari itu,', '', 'https://everyayah.com/data/Alafasy_128kbps/073003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:4', 73, 4, 29, 574, 5479, 'اَوْ زِدْ عَلَيْهِ وَرَتِّلِ الْقُرْاٰنَ تَرْتِيْلًاۗ', 'atau lebih dari (seperdua) itu. Bacalah Al-Qur’an itu dengan perlahan-lahan.', '', 'https://everyayah.com/data/Alafasy_128kbps/073004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:5', 73, 5, 29, 574, 5480, 'اِنَّا سَنُلْقِيْ عَلَيْكَ قَوْلًا ثَقِيْلًا', 'Sesungguhnya Kami akan menurunkan perkataan yang berat kepadamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/073005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:6', 73, 6, 29, 574, 5481, 'اِنَّ نَاشِئَةَ الَّيْلِ هِيَ اَشَدُّ وَطْـًٔا وَّاَقْوَمُ قِيْلًاۗ', 'Sesungguhnya bangun malam itu lebih kuat (pengaruhnya terhadap jiwa) dan lebih mantap ucapannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/073006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:7', 73, 7, 29, 574, 5482, 'اِنَّ لَكَ فِى النَّهَارِ سَبْحًا طَوِيْلًاۗ', 'Sesungguhnya pada siang hari engkau memiliki kesibukan yang panjang.', '', 'https://everyayah.com/data/Alafasy_128kbps/073007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:8', 73, 8, 29, 574, 5483, 'وَاذْكُرِ اسْمَ رَبِّكَ وَتَبَتَّلْ اِلَيْهِ تَبْتِيْلًاۗ', 'Sebutlah nama Tuhanmu dan beribadahlah kepada-Nya dengan sepenuh hati. ', '', 'https://everyayah.com/data/Alafasy_128kbps/073008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:9', 73, 9, 29, 574, 5484, 'رَبُّ الْمَشْرِقِ وَالْمَغْرِبِ لَآ اِلٰهَ اِلَّا هُوَ فَاتَّخِذْهُ وَكِيْلًا', '(Allah) adalah Tuhan timur dan barat. Tidak ada tuhan selain Dia. Maka, jadikanlah Dia sebagai pelindung.', '', 'https://everyayah.com/data/Alafasy_128kbps/073009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:10', 73, 10, 29, 574, 5485, 'وَاصْبِرْ عَلٰى مَا يَقُوْلُوْنَ وَاهْجُرْهُمْ هَجْرًا جَمِيْلًا ', 'Bersabarlah (Nabi Muhammad) terhadap apa yang mereka katakan dan tinggalkanlah mereka dengan cara yang baik.', '', 'https://everyayah.com/data/Alafasy_128kbps/073010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('73:11', 73, 11, 29, 574, 5486, 'وَذَرْنِيْ وَالْمُكَذِّبِيْنَ اُولِى النَّعْمَةِ وَمَهِّلْهُمْ قَلِيْلًا ', 'Biarkanlah Aku (yang bertindak) terhadap para pendusta yang memiliki segala kenikmatan hidup dan berilah mereka penangguhan sementara.', '', 'https://everyayah.com/data/Alafasy_128kbps/073011.mp3');
PRAGMA foreign_keys = ON;
